    public async Task<IEnumerable<Entities.CareFiles>> AutoTaskDistribution( )
    {
      List<Entities.CareFiles> careFilesDetails = null;
      careFilesDetails = await CareFiles
    .Where(x => x.File != "Searches" && (x.AssignedTo == null) && (x.Status !="Closed") )
    .OrderByDescending(x => x.Date).ToListAsync();
     
      var procResultData = new List<CareFiles>();
      if (careFilesDetails.Count > 0)
      {
        if (careFilesDetails[0].AssignedTo == null)
        {
          var gdate = careFilesDetails[0].Date.ToString();
          string date = DateTime.Parse(gdate).ToString("yyyy-MM-dd");
          //var sqlCommand2 = "EXEC [dbo].[AssignPHA_Essilor] '" + 9 + "','" + 12 + "','" + date + "'";
          //var sqlCommand1 = "EXEC [dbo].[AutoAssignPha] '" + 31 + "','" + 22 + "','" + 23 + "','" + date + "'";
          //var res = await Set<CareFiles>().FromSqlRaw(sqlCommand2).ToListAsync();
          var sqlCommand1 = "EXEC [dbo].[EmployerPhaAssign] '" + date + "'";
          procResultData = await Set<CareFiles>().FromSqlRaw(sqlCommand1).ToListAsync();


          return procResultData;

        }
      }
      else
      {
        // const string sqlCommand = "Select * from CareFiles where [File]!='Searches' and [AssignedTo] IS NOT NULL";
        var sqlCommand = "EXEC [dbo].[sp_GetAutoAssignPHA]";
        procResultData = await Set<CareFiles>()
            .FromSqlRaw(sqlCommand)
            .ToListAsync();
        return procResultData;
      }
      return procResultData;
    }
  }

